export const level12 = {
  num: 12, name: "Signal Flow + Production", focus: "The 505 as a Studio",
  duration: "65 min",
  setup: "RC-505mkII connected to computer via USB. DAW available (Ableton/GarageBand). Studio monitoring or good headphones. All 5 tracks available.",
  exercises: [
    {
      id: "lo12e1", time: 10, title: "The Sonic Audit", type: "looper",
      checklist: true,
      what: "Record a full multi-track performance via USB into your DAW. Listen back on studio monitors or quality headphones and identify the three biggest sonic issues. This is the diagnostic that reveals what your ears have been ignoring during live performance — the frequency mud, the volume inconsistencies, the noise floor.",
      setup: "RC-505mkII connected via USB to computer. DAW open with 505 selected as input device. Good headphones or studio monitors.",
      steps: [
        { text: "Connect the 505 to your computer via USB. In your DAW (Ableton/GarageBand), select the RC-505 as your audio input device. Arm a stereo track to record the 505's main mix output.", why: "USB recording captures the exact output of the 505 — no room acoustics, no microphone coloration. What you hear in the DAW is exactly what the 505 is producing. This is the most honest mirror for your loop quality." },
        { text: "Perform a full song: build up 4-5 tracks with rhythm, bass, chords, melody, and texture. Play for 3-5 minutes. Record the entire performance in the DAW.", why: "You need a full arrangement to audit — solo loops don't reveal mix problems. The issues emerge when multiple tracks interact: frequency masking, volume fights, and noise accumulation." },
        { text: "Stop the 505. Play back the DAW recording. Listen on your best headphones or monitors. Close your eyes and focus on the sound, not the memory of the performance.", why: "Playback separates the sound from the experience. While performing, adrenaline and focus mask problems. On playback, your ears are free to hear issues without distraction. This is why every producer listens back — the performance and the recording are different experiences." },
        { text: "Identify the three biggest sonic issues. Common culprits: (a) frequency mud in 200-400Hz — multiple tracks fighting for the low-mid range, (b) volume inconsistency — some tracks too loud, others buried, (c) noise floor — hiss, hum, or room noise audible during quiet passages.", why: "Three issues is manageable. Identifying twenty problems leads to paralysis. The top three are your highest-impact improvement targets. Fix those and the overall quality jumps dramatically." },
        { text: "Write down the three issues with specific descriptions: not 'it sounds bad' but 'Track 3 guitar chords are muddy in the low-mids' or 'Track 1 percussion has audible hiss between hits.' Specific diagnosis leads to specific fixes.", why: "Vague problems get vague solutions. Specific problems get specific solutions. 'Muddy low-mids on T3' leads directly to 'cut 200-400Hz on T3 EQ.' 'It sounds bad' leads to frustration." }
      ],
      feel: "Like getting an honest photo of yourself instead of a mirror selfie — you see things you've been unconsciously ignoring. The sonic audit is uncomfortable but invaluable. Every professional producer starts a mix session by listening critically before touching any controls.",
      wrong: "If you can't hear any problems, your monitoring isn't good enough or your ears haven't calibrated. Try different headphones or speakers — problems hidden on one system are revealed on another. Also: don't try to fix everything during the audit. Diagnose first, treat later. This exercise is ONLY about identification.",
      sarah: "Gene, the sonic audit reveals what your ears have been ignoring. It's like seeing your posture in a mirror for the first time — 'I've been slouching THAT much?' The recording doesn't lie. Your three biggest issues are your three biggest opportunities to level up. Write them down. We'll fix them in the next exercises.",
      metronome: 95,
      levelUp: "Can identify 3 specific sonic issues from a recorded performance with enough detail to prescribe EQ, level, or noise fixes for each one."
    },
    {
      id: "lo12e2", time: 8, title: "USB Audio Interface Mode", type: "looper",
      checklist: true,
      what: "The 505's most underused production feature: VENDOR USB mode turns it into an 8-channel USB audio interface. Each track records as a separate channel in your DAW — you can remix individual loop tracks after the performance. This is the bridge between live looping and studio production.",
      setup: "RC-505mkII connected via USB to computer. DAW open. No loops recorded yet.",
      steps: [
        { text: "Set USB MODE to VENDOR: [MENU > SYSTEM > USB > USB MODE > VENDOR]. The 505 restarts in interface mode. Your computer should recognize it as a multi-channel audio device.", why: "VENDOR mode exposes the 505's individual track outputs as separate USB audio channels. In GENERIC mode, you only get a stereo mix. VENDOR mode gives you per-track access — the difference between a photograph and a layered Photoshop file." },
        { text: "In your DAW, select the RC-505 as your audio input device. You should see multiple input channels available — typically channels 1-2 for the main mix, and additional channels for individual tracks.", why: "Each channel pair carries a different track's audio. This means you can record Track 1 on DAW channel 1, Track 2 on DAW channel 2, etc. Independent recording of each loop track." },
        { text: "Arm separate DAW tracks for each 505 channel. Label them: '505 T1,' '505 T2,' etc. Set each to record from the corresponding input channel.", why: "Labeling keeps the session organized. When you play back the DAW recording, you'll see each loop track as a separate waveform — solo, mute, and adjust each independently." },
        { text: "Record a simple 3-track performance on the 505 (rhythm, bass, chords). Watch the DAW — each track's audio appears on its own DAW channel in real time.", why: "Seeing the waveforms appear track by track is revelatory. You can see timing accuracy visually — a tight waveform aligned to the grid vs. a drifting one. Visual feedback complements what your ears tell you." },
        { text: "Stop the 505 and play back in the DAW. Solo each 505 track individually — listen to the rhythm alone, the bass alone, the chords alone. Problems invisible during combined playback become obvious in solo.", why: "Solo playback is the X-ray of your performance. That subtle timing drift on T3 that was masked by T1 and T2? Now it's exposed. The hiss on T1 that was hidden under the chords? Now it's obvious. This is how producers find and fix problems." }
      ],
      feel: "Like switching from a polaroid camera to a DSLR with RAW files — you're capturing all the data, not just the processed output. VENDOR mode gives you creative control AFTER the performance that you never had before. The performance is the capture. The DAW is the darkroom.",
      wrong: "If the DAW doesn't see the 505, check that USB MODE is set to VENDOR (not GENERIC). Also: some DAWs need the 505 plugged in BEFORE opening the DAW — quit and relaunch the DAW with the 505 already connected. On Windows, you may need the Boss USB driver installed (download from boss.info).",
      sarah: "Gene, VENDOR mode turns your looper into a recording studio. This is the feature that separates the 505 from every other looper — multi-track USB recording means your live performance can become a studio production. Every performance is now a recording session. Every recording session is recoverable, remixable, and refinable.",
      metronome: 95,
      levelUp: "Can set up VENDOR USB mode and record a multi-track performance into a DAW with separate channels for each 505 track. Can solo each track independently in the DAW."
    },
    {
      id: "lo12e3", time: 10, title: "Multi-Track USB Recording", type: "looper",
      checklist: true,
      what: "Record all 5 tracks as separate channels into your DAW, then analyze each track in isolation. This is the production workflow that turns a live loop performance into a studio-quality recording — capture live, refine in post.",
      setup: "RC-505mkII in VENDOR USB mode, connected to DAW. 5 DAW tracks armed for 505 input channels. Rhythm guide at 95 BPM.",
      steps: [
        { text: "Build a full 5-track arrangement on the 505: T1 percussion, T2 bass, T3 chords, T4 melody, T5 texture/color. Perform for 3-4 minutes while the DAW records all channels simultaneously.", why: "A full arrangement gives you the most data to work with. Five tracks means five independent audio streams in the DAW — each one a window into a specific aspect of your performance." },
        { text: "Stop the performance. In the DAW, solo Track 1 (percussion). Listen critically: is the timing tight? Are the hits consistent? Is there hiss or room noise between hits? Note any issues.", why: "Solo percussion reveals timing accuracy — every early hit, late hit, and inconsistent volume is exposed. Percussion is the foundation; timing problems here propagate to every other track." },
        { text: "Solo Track 2 (bass). Listen: are the notes clean? Is the pitch consistent? Is there fret buzz or finger noise? Does the bass line groove or does it plod?", why: "Bass in solo reveals intonation and tone issues. A bass line that sounds fine under chords might have pitch wobble or inconsistent attack that the chords were masking." },
        { text: "Solo each remaining track (T3, T4, T5) and note issues. Then play them back in pairs: T1+T2, T2+T3, T3+T4. Each combination reveals different relationship problems — timing alignment, frequency conflicts, volume balance.", why: "Paired playback reveals interaction issues. T2+T3 might show that bass and chords have conflicting low-mid frequencies. T3+T4 might show that chords and melody are fighting for the same register. These issues are invisible when all 5 play together." },
        { text: "In the DAW, adjust individual track volumes to create a better mix than the live fader positions achieved. Add subtle DAW reverb or EQ if desired. Export the result as a stereo file. Compare it to your live performance — the DAW mix should sound noticeably more polished.", why: "This is the payoff of multi-track recording: post-performance remixing. Your live fader positions were approximate. The DAW lets you be precise. The difference between a live mix and a DAW mix is the difference between 'pretty good' and 'professional.'" }
      ],
      feel: "Like a sports team reviewing game film — you see things in playback that you couldn't see in the moment. Every loop has a story to tell when you solo it: here's where you rushed, here's where you nailed it, here's where the tone dropped off. The multi-track recording is your coach's film room.",
      wrong: "If tracks are bleeding into each other (hearing T3's audio on T1's channel), check your DAW routing — each DAW track should be assigned to a specific 505 input channel, not 'all inputs.' Also: if some tracks are missing, make sure all 505 tracks had content during the performance — empty 505 tracks produce empty DAW channels.",
      sarah: "Gene, multi-track recording is the X-ray of your performance. Every strength and every weakness is exposed when you solo each track. It's not about being critical — it's about being honest. The tracks that sound great in solo are your strengths to build on. The tracks with issues are your specific, targeted improvement areas.",
      metronome: 95,
      levelUp: "Can record a full 5-track performance as separate DAW channels, solo each track for analysis, and create a remixed version that sounds noticeably better than the live mix."
    },
    {
      id: "lo12e4", time: 10, title: "Per-Track EQ Mastery", type: "looper",
      checklist: true,
      what: "Deep EQ work using the 505's Track FX. Each track occupies a frequency zone, and EQ surgery removes problems and enhances strengths. The goal is clarity — every track should be audible and distinct when all five play together.",
      setup: "RC-505mkII with a full 5-track arrangement playing. Headphones (critical for EQ work — room acoustics will fool you).",
      steps: [
        { text: "T1 percussion EQ: [MENU > TRACK 1 > TRACK FX > EQ]. Boost 3-5kHz by 3-4dB to enhance attack and click. Cut 200Hz by 3-4dB to reduce mud and boominess. A/B: bypass the EQ, listen, engage it, listen. The EQ'd version should sound crisper, not different.", why: "Percussion lives in the high frequencies — the click of a muted string, the snap of a body tap. Boosting 3-5kHz makes those attacks cut through the mix. Cutting 200Hz removes low-frequency rumble that percussion doesn't need and that conflicts with bass." },
        { text: "T2 bass EQ: boost 80-120Hz by 2-3dB to enhance body and warmth. Cut 800Hz by 3-4dB to remove honk and nasal quality. A/B test.", why: "Bass needs low-end weight (80-120Hz) to feel solid. The 800Hz region is where bass sounds honky and boxy — cutting it opens up space and lets the fundamental shine through." },
        { text: "T3 guitar chords EQ: cut 200-400Hz by 3-5dB to remove mud. Boost 2-4kHz by 2-3dB to enhance presence and string definition. A/B test.", why: "Guitar chords are the worst frequency offenders — they produce massive energy in the 200-400Hz mud zone. Cutting here is the single biggest improvement you can make to a loop mix. The 2-4kHz boost adds the shimmer and detail that makes chords sparkle instead of thud." },
        { text: "T4 melody EQ: boost 1-3kHz by 2-3dB to enhance clarity and projection. Cut sub-bass (below 100Hz) completely — melody instruments don't need sub-bass and it only adds rumble. A/B test.", why: "The 1-3kHz range is where human hearing is most sensitive — boosting here makes the melody feel closer and more present. Cutting sub-bass is free headroom — it removes energy you can't hear from an instrument that doesn't produce meaningful bass." },
        { text: "T5 texture EQ: high-pass filter at 200Hz — remove everything below 200Hz. Textures, effects, and atmospheric elements don't need low-frequency content. This prevents frequency conflict with T1 and T2. A/B test.", why: "High-passing texture tracks is the simplest way to clean up a mix. Reversed guitar, effects, and pads produce low-frequency content you don't need and don't notice until it conflicts with bass and percussion. Removing it is free clarity." }
      ],
      feel: "Like tuning a choir — each voice is beautiful, but they need to occupy their own space to blend without fighting. EQ is the tool that gives each track its own frequency home. After EQ, the mix should sound wider, clearer, and more three-dimensional — like the tracks are standing in a line across the soundstage instead of piled on top of each other.",
      wrong: "If EQ makes things sound worse, you're boosting too much. EQ is surgery, not seasoning — small moves, precise targets. A 3dB boost is subtle. A 10dB boost is a problem. Also: always A/B test. The human ear adjusts to whatever it's hearing within seconds — you need the bypass comparison to judge accurately. And ALWAYS EQ on headphones, not speakers, because room acoustics add their own EQ that masks the changes you're making.",
      sarah: "Gene, EQ is surgery — remove problems, enhance strengths. The frequency chart is your surgical plan: cut mud on chords, boost attack on percussion, warm up bass, clarify melody. Each cut and boost has a reason. After EQ, your five tracks should each have their own frequency space — no fighting, no masking, just clarity.",
      metronome: 95,
      levelUp: "Can EQ all 5 tracks with specific frequency targets. The EQ'd mix sounds noticeably clearer than the un-EQ'd version. Can explain why each EQ move was made."
    },
    {
      id: "lo12e5", time: 5, title: "Noise Floor Management", type: "looper",
      checklist: true,
      what: "Reduce hiss, hum, and room noise to inaudible levels. The noise floor is the sonic background of silence — and in loop performance, noise accumulates with each track. Five tracks of slight hiss become one track of obvious hiss. Managing noise is managing professional quality.",
      setup: "RC-505mkII with headphones. Quiet room. Guitar connected to INST input.",
      steps: [
        { text: "Measure your noise floor: record an empty loop on T1 — press Record, play NOTHING for 4 bars, press Stop. Turn the fader to 100%. Listen on headphones. What do you hear? Hiss? Hum? Room noise? This is your noise floor.", why: "The empty-loop test reveals everything your signal chain adds to silence. Any hiss, hum, or buzz you hear will be present on EVERY loop you record. It accumulates — five tracks of quiet hiss become one mix of audible hiss." },
        { text: "Identify noise sources: (a) High input gain = hiss (turn down if signal permits), (b) Room noise = AC hum, computer fans, street noise (close-mic to improve signal-to-noise ratio), (c) Ground loops = 60Hz hum from power (try a DI box or ground lift adapter).", why: "Each noise source has a different fix. Hiss is gain-related — lower the input gain and play closer to the mic or louder into the guitar pickup. Hum is electrical — ground loops between amp, 505, and computer. Room noise is environmental — you can't EQ it out, only reduce it at the source." },
        { text: "Set the 505's noise gate: [MENU > INPUT > NOISE GATE]. Start with the threshold at the lowest setting. Gradually raise it until the noise disappears during silence but your quiet playing still comes through.", why: "The noise gate closes the input when the signal drops below the threshold — silencing noise between notes. Too aggressive = cuts off quiet notes and note tails. Too gentle = noise bleeds through during pauses. The right setting is a balance point that depends on your specific noise floor." },
        { text: "Test the noise gate: play a quiet passage, then stop. The gate should close smoothly — noise disappears without an audible 'click' or abrupt cutoff. If the cutoff is audible, lower the threshold slightly.", why: "An audible gate close is worse than the noise it's trying to hide. The gate should be transparent — the audience should never know it's there. If you can hear it working, it's set too aggressively." },
        { text: "Record a 5-track arrangement with the noise gate active. Compare to your earlier recordings (exercise 1). The noise floor should be noticeably lower during quiet passages and between notes.", why: "The proof is in the comparison. A clean noise floor makes your quiet passages truly quiet — which makes your loud passages feel louder by contrast. Dynamic range improves when the silence is actually silent." }
      ],
      feel: "Like cleaning a window — you don't notice how dirty it was until you see through the clean glass. A low noise floor makes everything else sound better because the quiet moments are actually quiet. The music emerges from silence instead of from hiss.",
      wrong: "If the noise gate is chopping off the beginning of your notes (especially quiet ones), the threshold is too high — lower it. If you still hear noise with the gate on, the noise is louder than your quiet playing — the gate can't distinguish between the two. In that case, fix the noise at the source: lower gain, move away from noise sources, check grounding.",
      sarah: "Gene, the quietest part of your music reveals the noise floor. When your loops are playing, noise is masked. When they stop, noise is exposed. A professional recording has a silent noise floor — the silence between notes is ACTUALLY silent. Get your noise floor down and your loops will sound like studio recordings, not bedroom demos.",
      metronome: 95,
      levelUp: "Noise floor inaudible at normal listening levels with 5 tracks playing. Noise gate set correctly — no audible gate artifacts (clicks, cutoffs) during quiet passages."
    },
    {
      id: "lo12e6", time: 8, title: "Master FX", type: "looper",
      checklist: true,
      what: "The 505's Master FX applies to the ENTIRE output — all tracks combined. Unlike Track FX (which affects one track), Master FX is your mastering chain. Use it sparingly: light compression, limiting, and gentle EQ. Heavy effects on the master bus destroy track separation and create mud.",
      setup: "RC-505mkII with a full 5-track arrangement playing. Good headphones.",
      steps: [
        { text: "Access Master FX: [MENU > MASTER FX]. Browse the available effects. Note that these apply to ALL tracks simultaneously — not just one track.", why: "Master FX is the last stage before the output. Everything passes through it. This means any effect you apply here affects percussion, bass, chords, melody, and texture equally. It's a blunt instrument — powerful but indiscriminate." },
        { text: "Apply light compression: select a compressor effect with low ratio (2:1 or 3:1) and moderate threshold. Listen to the result — the loud parts get slightly quieter and the quiet parts stay the same. The overall volume feels more consistent.", why: "Master compression evens out the dynamic range of the entire mix. Without it, your fader-riding must be perfect. With it, small volume inconsistencies are automatically smoothed. Light compression is the glue that holds a mix together. Heavy compression squashes the life out of it." },
        { text: "Apply a limiter: set the ceiling just below 0dB (clipping point). The limiter catches any volume spikes that would cause distortion. Play your loudest section — the limiter should engage only on peaks, not constantly.", why: "Limiting prevents clipping — the harsh distortion that happens when audio exceeds 0dB. In a live looping context, volume spikes happen when multiple tracks peak simultaneously. The limiter catches these moments and prevents the ugly crunch of digital distortion." },
        { text: "Try a gentle master EQ: a subtle low-end boost at 80Hz (adds warmth to the whole mix) and a subtle high-end boost at 10kHz (adds air and sparkle). Changes should be 1-2dB maximum. A/B test to confirm improvement.", why: "Master EQ is room correction and tonal shaping for the entire mix. In a boomy room, cut low-mids. In a dead room, boost high-end air. The changes are tiny because they affect everything — a 2dB boost at 80Hz is warmth, a 6dB boost at 80Hz is mud." },
        { text: "A/B the Master FX: bypass it completely, listen to the raw mix. Engage it, listen to the processed mix. The difference should be subtle but clear — tighter, more controlled, slightly wider. If the difference is dramatic, you're using too much. Pull it back.", why: "The best mastering is invisible. The listener shouldn't notice it — they should just notice that the music sounds 'good.' If the Master FX is obviously changing the sound, it's doing too much. Mastering is a gentle hand, not a heavy fist." }
      ],
      feel: "Like the final polish on a guitar — it doesn't change the wood or the shape, just makes it shine. Master FX is the production polish that takes a good loop performance and makes it sound finished. The audience won't know why it sounds better. They'll just feel it.",
      wrong: "Do NOT use chorus, flanger, heavy reverb, or distortion as Master FX — these destroy track separation and turn your mix into mush. Master FX is ONLY for dynamics processing (compression, limiting) and gentle tonal shaping (EQ). If your Master FX makes the mix sound worse than no Master FX, turn it off. Less is more.",
      sarah: "Gene, Master FX is the mastering engineer — gentle touch, big impact. Think of it like the final step in developing a photograph: you're not changing the composition or the subject, just making the colors pop and the contrast sit right. Light compression, a limiter for safety, and maybe a whisper of EQ. That's all. If you can hear the Master FX working, it's too much.",
      metronome: 95,
      levelUp: "Master FX chain set up with light compression and limiting. A/B test shows subtle but clear improvement over the raw mix. No audible artifacts or mud."
    },
    {
      id: "lo12e7", time: 5, title: "Multi-Output Routing", type: "looper",
      checklist: true,
      what: "Route different tracks to different physical outputs on the 505. Main output goes to FOH (front of house) or PA system. Sub output goes to a separate monitor. Headphones carry your personal mix with rhythm guide. This is the professional live setup — the audience hears one thing, you hear another.",
      setup: "RC-505mkII with loops playing. Main output connected to speakers or interface. Sub output available (TRS cable). Headphones connected.",
      steps: [
        { text: "Understand the 505's outputs: MAIN OUTPUT (1/4\" TRS L/R) = primary audio to PA or speakers. SUB OUTPUT (1/4\" TRS) = secondary audio for separate routing. PHONES = headphone jack with independent level control.", why: "Three separate output paths give you three separate mixes. In a live venue: MAIN goes to the PA (audience mix), SUB goes to your stage monitor (personal mix), PHONES gives you the rhythm guide and private monitoring." },
        { text: "Route a track to sub output: [MENU > TRACK > OUTPUT > SUB]. Try routing T1 (percussion) to SUB while all other tracks go to MAIN. Now you can hear percussion separately on the sub output.", why: "Separating a track to the sub output lets you monitor it independently. Use case: send your click/percussion to a personal monitor so you always hear the groove clearly, even if the main PA is feeding back or the room acoustics are bad." },
        { text: "Verify routing: listen to the MAIN output — T1 should be absent. Listen to the SUB output — T1 should be the only thing playing. Adjust the routing so T1 goes to BOTH main and sub if you want the audience to hear it too.", why: "Routing verification prevents surprises during performance. The worst version: your rhythm guide going to the main PA and the entire venue hearing your click track. Always verify routing before going live." },
        { text: "Set headphone level independently: the headphone volume knob on the 505 is separate from the main output level. Set headphones louder than main for personal monitoring without blasting the audience.", why: "Independent headphone level means you can hear yourself clearly regardless of the PA volume. In a quiet venue, keep the PA moderate. In a loud venue, crank the PA. Either way, your headphones stay at YOUR comfortable level." },
        { text: "Confirm: rhythm guide is in PHONES only (not MAIN, not SUB). Loops are in MAIN (and optionally SUB). Your live input is in both MAIN and PHONES. This is the standard live routing setup.", why: "The standard setup: audience hears loops + live performance. You hear loops + live performance + rhythm guide. The rhythm guide NEVER goes to the audience. This routing is your default for every live performance." }
      ],
      feel: "Like a stage setup where the musician has in-ear monitors that carry a different mix than the front-of-house speakers. The audience hears the show. You hear the tools you need to deliver the show. Output routing is the infrastructure that makes professional live looping possible.",
      wrong: "If the rhythm guide is audible in the main output, your routing is wrong — the audience should NEVER hear the click. Check [MENU > RHYTHM > OUTPUT] and ensure it's set to PHONES or HEADPHONE only. Also: if you're hearing feedback, check that SUB output isn't feeding back into an input somewhere in your signal chain.",
      sarah: "Gene, output routing is for live venues — separate what you hear from what the audience hears. You need the rhythm guide to stay in time. The audience needs to hear only the music. Multi-output routing makes both possible simultaneously. Set this up once and it becomes your standard live configuration.",
      metronome: 95,
      levelUp: "Can route specific tracks to MAIN vs SUB output. Rhythm guide confirmed PHONES-only. Headphone level set independently of main output."
    },
    {
      id: "lo12e8", time: 5, title: "Monitoring Setup", type: "looper",
      checklist: true,
      what: "Professional monitoring: your headphones carry a private mix that includes everything the audience hears PLUS your rhythm guide and any personal reference tracks. The main output carries only the performance. Getting this right means you always perform confidently regardless of venue acoustics.",
      setup: "RC-505mkII with loops playing. Headphones connected. Main output connected to speakers.",
      steps: [
        { text: "Set headphone source: [MENU > SYSTEM > OUTPUT > PHONES]. Ensure it includes all tracks + rhythm guide. The headphone mix is your private cockpit — everything you need to perform.", why: "Your headphones are your control center. You need to hear every track clearly, plus the rhythm guide that the audience can't hear. Missing any element in your headphones means flying blind during that part of the performance." },
        { text: "Set headphone level to a comfortable monitoring volume — loud enough to hear detail over room noise, quiet enough to protect your hearing for a full set. Test with your loudest loop configuration.", why: "Monitoring volume is a balance between hearing detail and preserving your hearing. Too quiet and you miss problems. Too loud and you get ear fatigue (and eventual hearing damage). Find your comfortable level and leave it there for the set." },
        { text: "Verify rhythm guide isolation: play your loops through the main output. Put on headphones — you should hear loops + rhythm guide. Remove headphones and listen to the main output — you should hear loops only, NO rhythm guide.", why: "This is the critical check. If you hear the click through the main speakers, your routing is wrong. This verification should happen before EVERY performance, even if you're sure it's right. Paranoia about click bleed is healthy." },
        { text: "Test the monitoring in context: play a full performance with headphones on, focusing on the private mix. Can you hear the rhythm guide clearly? Can you distinguish each track? Can you hear your live input? If any element is missing or unclear, adjust the headphone mix.", why: "A monitoring test under performance conditions reveals issues that static testing misses. When you're singing, playing guitar, and triggering tracks simultaneously, your attention is divided — the monitoring mix needs to be clear enough to cut through divided attention." },
        { text: "Practice performing with headphones: play a full song while monitoring. The headphones should feel like a benefit (confidence, clarity, rhythm reference) not a distraction (too loud, uncomfortable, disorienting). If they feel wrong, adjust until they feel right.", why: "Some performers find headphones disorienting — the in-head sound conflicts with the room sound. If this is you, try half-on monitoring (one ear covered, one ear open to the room). Or use the 505's sub output to a floor monitor instead of headphones. Find what works for YOUR performance comfort." }
      ],
      feel: "Like a pilot's headset — it carries the information you need to fly safely (rhythm guide, track levels, live input) without broadcasting your private communications to the passengers (audience). Monitoring is your private channel. It exists to serve your performance, not the audience's experience.",
      wrong: "If monitoring feels disorienting, try one ear on/one ear off until you're used to it. If the rhythm guide is too loud relative to the loops, adjust the rhythm guide level (not the headphone level — that affects everything). If you can't hear your live voice over the loops in headphones, add more live input to the headphone mix.",
      sarah: "Gene, monitoring is your private mix — it should help you perform, not distract you. The rhythm guide in your ear keeps you locked to the grid. The loop playback in your ear confirms what the audience is hearing. Your live input in your ear lets you hear yourself clearly. When all three are balanced, performing feels effortless because you have all the information you need.",
      metronome: 95,
      levelUp: "Monitoring setup complete: headphones carry all tracks + rhythm guide + live input. Rhythm guide confirmed absent from main output. Headphone level comfortable for a full set."
    },
    {
      id: "lo12e9", time: 8, title: "The A/B Reference Test", type: "looper",
      checklist: true,
      what: "Play your loop performance next to a professional recording in the same genre. What's different? This is not about matching the pro recording — it's about identifying the specific gaps between your loop output and commercial music. Each gap is a targeted improvement area.",
      setup: "RC-505mkII with a recorded performance (USB or direct monitoring). A professional reference track in a similar genre (Khruangbin, Allah-Las, Skinshape, etc.) ready to play on phone or computer. Same headphones for both.",
      steps: [
        { text: "Choose a reference track: pick a song in your genre that represents the sound you're aiming for. Khruangbin 'Maria Tambien,' Allah-Las 'Tell Me,' or Skinshape 'I Didn't Know' are good references for your style.", why: "The reference track is your target. It represents professional production quality in a genre you love and play. Comparing against it reveals specific production gaps — not 'is my music good enough' but 'what specifically sounds different.'" },
        { text: "Play 30 seconds of the reference track. Immediately switch to 30 seconds of your loop performance. Back and forth, 3 times. Focus on frequency balance: does the reference sound wider, fuller, brighter? Where specifically?", why: "Rapid A/B switching prevents your ears from adjusting. If you listen to your loops for 2 minutes, your brain normalizes the sound. Switching every 30 seconds keeps the comparison fresh and the differences stark." },
        { text: "Note the differences in three categories: (a) Frequency balance — pro recordings are usually wider and clearer with more defined low-end and sparkling highs. (b) Dynamic range — pro recordings breathe, with volume rising and falling naturally. (c) Clarity — individual elements in pro recordings are distinct and separable.", why: "Three categories keeps the analysis focused. Frequency balance is EQ territory. Dynamic range is compression and performance territory. Clarity is arrangement and mixing territory. Each category has specific tools and techniques for improvement." },
        { text: "Identify ONE specific, actionable improvement: 'My bass is muddy compared to the reference — I need to cut 200Hz on T2' or 'My dynamics are flat — I need more fader movement.' ONE improvement you can implement right now.", why: "One actionable improvement is better than ten vague observations. If you fix one thing every practice session, you improve steadily. If you identify ten problems and fix none, you stay stuck. Pick the biggest gap. Fix it. Move on." },
        { text: "Implement the improvement on the 505 (EQ, levels, performance technique). Then A/B test again. Did the gap shrink? If yes, note what you did and repeat the process next session. If no, reassess and try a different fix.", why: "The A/B test is both diagnostic and verification. It tells you what's wrong AND whether your fix worked. This close-loop feedback cycle is how professional producers refine their sound — listen, adjust, compare, repeat." }
      ],
      feel: "Like a cooking student tasting their dish next to a Michelin-starred version of the same recipe. The ingredients are the same. The techniques are different. The comparison reveals WHICH techniques to improve — seasoning? Temperature? Plating? — without the judgment of 'mine is bad.' It's not bad. It's learning.",
      wrong: "Don't try to match the pro recording — they had a studio, engineers, mixing, and mastering. The goal is to close the gap, not eliminate it. Also: don't compare against heavily produced electronic music — compare against artists whose sound is achievable with a looper and guitar. Khruangbin, Skinshape, and DOPE LEMON are achievable references. Radiohead is not.",
      sarah: "Gene, A/B testing against pros is humbling but invaluable. The pro recording had a studio, a mixer, a mastering engineer. You have a 505 and headphones. But the gap is smaller than you think — and every gap you identify is a specific skill you can develop. One improvement per session adds up fast.",
      metronome: 95,
      levelUp: "Can identify 3 specific differences between your loop output and a professional reference. Can implement at least 1 improvement and verify it via A/B comparison."
    },
    {
      id: "lo12e10", time: 5, title: "Volume Automation via Faders", type: "looper",
      checklist: true,
      what: "Program yourself to make specific fader moves at specific song moments. This is 'manual automation' — the 505 equivalent of DAW automation curves. Written fader maps turn vague dynamics into precise, repeatable performance decisions.",
      setup: "RC-505mkII with a full arrangement playing. Paper and pen for the fader map. Rhythm guide at 95 BPM.",
      steps: [
        { text: "Write a fader map for T3 (chords): 'Bar 1-8: T3 at 50%. Bar 9-16: T3 fades to 80%. Bar 17-20: T3 cuts to 0%. Bar 21-24: T3 slams to 100%.' This is your automation script.", why: "A written fader map turns vague 'make it dynamic' into specific 'move this fader to this level at this bar.' Precision is the difference between intentional dynamics and random volume changes." },
        { text: "Practice the fader moves with the loop playing. Count bars: 1-2-3-4, 2-2-3-4... At bar 9, start moving T3 fader from 50% to 80% over 8 bars. At bar 17, pull it to zero. At bar 21, push it to max.", why: "Fader moves are a physical skill like any instrument technique — they need practice. The move from 50% to 80% over 8 bars should be smooth and gradual. The cut to 0% should be sudden. The slam to 100% should be dramatic. Each move has a different physical gesture." },
        { text: "Add a T4 (melody) fader map that complements T3: when T3 drops, T4 rises. When T3 returns, T4 pulls back. The two faders move in counterpoint — one up, the other down.", why: "Complementary fader moves create arrangement dynamics. When chords drop out and melody rises, the texture changes from harmonic to melodic. When chords return full and melody recedes, the texture fills out again. This is arranging via volume, not via content." },
        { text: "Rehearse the full fader map 5 times. Each run should feel more natural and less like reading a script. By run 5, the moves should be approaching muscle memory.", why: "Fader moves need the same repetition as chord changes or drum patterns. Five reps is the minimum for initial motor learning. The goal is that bar 17 FEELS like the moment to pull T3 down, not that you REMEMBER it's bar 17." },
        { text: "Record a performance with your fader map executed. Play it back. Do the dynamics sound intentional? Does the volume arc create emotional movement? If the dynamics sound random, your timing is off — back to the map.", why: "The playback test reveals whether your fader moves are serving the music or distracting from it. Intentional dynamics feel like the song is breathing. Random dynamics feel like someone is playing with the volume knob. If it doesn't feel right, simplify the map." }
      ],
      feel: "Like a lighting designer programming cues for a theater show — when the lights dim here and brighten there, the audience feels the drama without knowing why. Your fader moves are lighting cues for your loop performance. The audience feels the dynamics. They don't see the faders.",
      wrong: "If fader moves feel frantic or chaotic, you're doing too much. Start with ONE fader move in the whole song (T3 fades up at the chorus). Add more moves only when the first one is automatic. Also: don't move faders during technically demanding passages — your hands are on the guitar. Move faders during simple or empty bars.",
      sarah: "Gene, planned fader moves are arrangement decisions — they're as important as the notes you play. A chord track that fades in slowly over 8 bars creates anticipation. One that slams in at full volume creates impact. Same notes, different dynamics, completely different emotional effect. Your faders are instruments. Play them.",
      metronome: 95,
      levelUp: "Can execute a written fader map for 2 tracks over a 32-bar arrangement. The dynamics sound intentional and serve the song's emotional arc."
    },
    {
      id: "lo12e11", time: 5, title: "Compression Concepts", type: "looper",
      checklist: true,
      what: "Understanding dynamic range in loops and how compression evens out volume inconsistencies. When your quiet verse loop gets buried under your loud chorus loop, that's a dynamic range mismatch. Track FX compression is the fix — and understanding it transforms your mix quality.",
      setup: "RC-505mkII with at least 2 tracks playing (one quiet, one loud). Headphones for critical listening.",
      steps: [
        { text: "Identify the problem: play a quiet fingerpicked verse loop (T3) alongside a loud strummed chorus loop (T4). The strumming buries the fingerpicking. This is dynamic range mismatch — the two tracks have very different volume envelopes.", why: "Dynamic range mismatch is the most common mix problem in looping. You record each track at its natural volume, but natural volumes vary wildly between fingerpicking (quiet) and strumming (loud). Without compression, you're constantly riding faders to compensate." },
        { text: "Apply Track FX compression to T4 (the loud track): [MENU > TRACK 4 > TRACK FX > COMPRESSOR]. Set ratio to 2:1 or 3:1. Set threshold so the compressor engages on the loudest hits.", why: "Compression reduces the dynamic range of a track — it turns down the loud parts while leaving the quiet parts alone. A 2:1 ratio means a 10dB peak becomes a 5dB peak. The result: T4 sounds more consistent in volume, and the peaks no longer bury T3." },
        { text: "A/B test: bypass the compressor, listen to T3+T4 together. Engage the compressor, listen again. With compression, T3 (fingerpicking) should be more audible because T4 (strumming) peaks are controlled.", why: "The A/B test proves the compression is working. The compressed version should sound more 'together' — like the two tracks belong in the same mix instead of fighting for attention." },
        { text: "Listen for artifacts: over-compression makes audio sound squashed, lifeless, or pumping (volume bouncing unnaturally). If you hear these, reduce the ratio (try 2:1) or raise the threshold (so the compressor engages less often).", why: "Compression is a scalpel, not a sledgehammer. Over-compression is worse than no compression — it sucks the life out of the performance. The goal is subtle control: the peaks come down slightly, the overall feel stays natural." },
        { text: "Try compression on T2 (bass). Bass guitar has wide dynamic range — plucked notes spike and fretted notes are quieter. Light compression (3:1, moderate threshold) evens out the bass line so every note has consistent weight in the mix.", why: "Bass benefits the most from compression because consistent low-end is the foundation of a good mix. An inconsistent bass line makes the whole arrangement feel unstable. Compression gives the bass authority and presence." }
      ],
      feel: "Like an automatic volume knob that turns down the loudest moments just enough to fit everything together. The dynamics are still there — just controlled. The music still breathes — it just doesn't gasp and whisper anymore. Compression is the glue that holds a mix together.",
      wrong: "If everything sounds flat and lifeless after compression, you're compressing too much. Reduce the ratio (1.5:1 or 2:1) and raise the threshold. The compressor should be invisible — catching peaks, not reshaping the entire dynamic range. Also: don't compress everything. Start with the loudest and most dynamic tracks. Leave tracks with consistent volume alone.",
      sarah: "Gene, compression is the glue that holds a mix together. When your quiet verse and loud chorus sit nicely next to each other without you riding the fader, that's compression working. It's the most important mixing tool after EQ — and on the 505, it's available as a Track FX on every track. Use it gently and your mixes will sound immediately more professional.",
      metronome: 95,
      levelUp: "Can apply appropriate compression to at least 2 tracks. The compressed mix sounds more balanced than the uncompressed mix without audible compression artifacts (pumping, squashing)."
    },
    {
      id: "lo12e12", time: 5, title: "Room Acoustics Awareness", type: "looper",
      checklist: true,
      what: "How the room affects your loop sound — and why your bedroom loops won't sound the same at a venue. Every room adds its own reverb, bass resonance, and frequency coloration. Learning to adjust for the space is the difference between a performance that sounds polished everywhere and one that only sounds good at home.",
      setup: "RC-505mkII with a full arrangement ready. Test in your practice room first, then mentally prepare for different venues.",
      steps: [
        { text: "Analyze your practice room: clap once and listen. How long does the clap ring? Short decay (under 0.5s) = dry room (bedroom, carpeted space). Long decay (over 1s) = reverberant room (tile, concrete, high ceilings). Your room type determines your EQ and effects starting point.", why: "The clap test reveals your room's natural reverb. A dry room needs more effects-added reverb. A reverberant room needs less (or the reverb stacks and creates mud). Knowing your room's character is the first step to compensating for it." },
        { text: "Test bass in your room: play a sustained low E on your guitar through the 505. Walk around the room. In some spots, the bass will be louder (standing waves) and in others it will disappear (null points). This is your room's bass response.", why: "Room modes (standing waves) cause certain bass frequencies to pile up in corners and cancel in other spots. If your listening position is in a bass null, you'll think you need more bass — and your loops will sound too bassy everywhere else. Awareness of room bass prevents over-correcting." },
        { text: "Adjust for a dry room: if your practice space is carpeted and small (low reverb), add a touch more reverb via Track FX to compensate. What sounds right in a dry room will sound DRY in a larger venue.", why: "Dry rooms absorb high frequencies and reduce natural reverb. Your loops sound close and intimate. In a larger venue, the room adds its own reverb, so the reverb you added at home might become too much. Adjust effects for the space you're in, not the space you practiced in." },
        { text: "Prepare for venue adjustment: make a note of your home EQ and reverb settings. At a venue, you'll need to reduce reverb (the room adds its own) and possibly cut low-mids (larger rooms emphasize 200-400Hz). Build these adjustments into your soundcheck routine.", why: "Your bedroom sound will NOT translate to a venue without adjustment. This is true for every musician, every producer, every sound engineer. The adjustment process is the soundcheck — and knowing what to adjust comes from understanding room acoustics." },
        { text: "Practice the mindset: 'this sounds good HERE' is different from 'this sounds good.' Always qualify your mix judgments with the room you're in. What sounds perfect in your bedroom may sound muddy at a coffee shop and thin in a concert hall.", why: "Room awareness prevents false confidence and false insecurity. Your loops don't suddenly get worse at a venue — the room changed. Your loops don't suddenly get better at home — the room is flattering. The truth is somewhere between the two extremes." }
      ],
      feel: "Like a photographer who adjusts white balance for different lighting — the subject is the same, but the light changes everything. Your loops are the subject. The room is the lighting. Learning to adjust for different rooms is learning to make your music sound good ANYWHERE, not just in your practice space.",
      wrong: "Don't over-correct for room acoustics in your practice space — extreme EQ to compensate for room modes will sound terrible everywhere else. Make moderate adjustments for your room, and save the fine-tuning for each venue's soundcheck. Also: if you're making critical mix decisions (EQ, compression, levels), use headphones to bypass the room entirely.",
      sarah: "Gene, the room is an instrument — learn to play it. Your bedroom is dry and intimate. A coffee shop is reflective and noisy. A venue is reverberant and bass-heavy. Each space changes how your loops sound, and each space needs different settings. This isn't a problem — it's a skill. Musicians who sound good everywhere have learned to adjust for the room.",
      metronome: 95,
      levelUp: "Can describe your practice room's acoustic character (reverb time, bass behavior). Can list 3 adjustments you'd make when moving to a larger, more reverberant venue."
    },
    {
      id: "lo12e13", time: 8, title: "The Radio-Ready Test", type: "looper",
      checklist: true,
      what: "Could this performance go on a podcast, radio show, or YouTube without apology? Score yourself across five production criteria: clean loops, balanced mix, low noise floor, clear vocal, intentional dynamics. 'Radio-ready' is a mindset — it means you care about how it sounds to others, not just to you.",
      setup: "RC-505mkII connected via USB to DAW. Full song performance ready. Quality headphones for critical playback.",
      steps: [
        { text: "Record a complete song performance — intro, verse, chorus, bridge, outro — via USB into your DAW. Perform it as if it's going on the radio. No restarts, no 'I'll fix it later.' This is a take.", why: "The 'radio test' requires a complete, uninterrupted performance. Restarts and fixes are studio luxuries. A radio-ready performance is one continuous take that sounds intentional from start to finish." },
        { text: "Play it back. Score yourself 1-5 on each criterion: (1) CLEAN LOOPS — no clicks, pops, or boundary artifacts. (2) BALANCED MIX — all tracks audible, nothing buried or overpowering. (3) LOW NOISE FLOOR — silence between notes is actually silent. (4) CLEAR VOCAL — lyrics intelligible, voice sits on top of the mix. (5) INTENTIONAL DYNAMICS — volume and texture change with purpose across sections.", why: "Five criteria, five scores. The lowest score is your most urgent improvement target. The highest score is your strength. Quantifying quality makes improvement measurable and trackable across sessions." },
        { text: "For any criterion below 3/5, write a specific improvement plan: 'Mix balance: T3 chords burying T4 melody. Fix: cut T3 by 3dB or EQ cut at 2kHz.' Specific diagnosis leads to specific action.", why: "A score without an action plan is just judgment. A score WITH an action plan is a learning tool. The plan turns 'my mix is unbalanced' into 'Track 3 needs a 3dB cut,' which is something you can actually do in the next practice session." },
        { text: "Play the recording for someone else — a friend, family member, or post it privately online. Ask: 'Does this sound like it could be on the radio?' Their reaction tells you more than your own assessment because they hear it fresh, without the performance memories.", why: "Self-assessment has a ceiling. You know what you INTENDED, so you hear intention even when it's not audible. A fresh listener hears only what's actually there. Their honest reaction is the most valuable feedback you can get." },
        { text: "Compare your score to last month's score (if available). Improvement over time is more important than any single score. Going from 2/5 to 3/5 on noise floor means your production skills are growing. Going from 3/5 to 4/5 on dynamics means your performance skills are growing.", why: "Progress tracking prevents both complacency and despair. If your scores improve month over month, you're on the right trajectory regardless of the absolute numbers. If they plateau, you need to change your practice approach." }
      ],
      feel: "Like submitting a draft to an editor — scary but clarifying. The radio-ready test forces you to hear your music as a LISTENER, not as a performer. Performers hear what they intended. Listeners hear what actually happened. Closing that gap is the journey from bedroom producer to professional.",
      wrong: "Don't be discouraged by low scores — they're diagnostic, not judgment. A 2/5 on clean loops means you have a specific, fixable problem, not that your music is bad. Also: don't inflate your scores to feel better. Honest self-assessment is the only kind that leads to improvement. A generous 4/5 that should be a 3/5 means you'll never fix the problem.",
      sarah: "Gene, 'radio-ready' is a mindset — it means you care about how it sounds to others, not just to you. The standard is: a stranger hearing this would assume it's a produced recording, not a guy with a looper. That's a high bar, and you're not expected to clear it immediately. But aiming for it every session will get you there faster than you think.",
      metronome: 95,
      levelUp: "Can score a complete performance across all 5 criteria. Average score of 3/5 or higher. Written improvement plan for any criterion below 3/5."
    },
    {
      id: "lo12e14", time: 10, title: "The Demo Recording", type: "looper",
      checklist: true,
      what: "Record a polished 3-song demo using USB multi-track recording. Mix in your DAW: adjust per-track levels, add subtle processing, normalize output. Export as WAV and MP3. This is your calling card — share it, post it, send it to venues. The demo proves you can deliver production-quality loop performances.",
      setup: "RC-505mkII in VENDOR USB mode, connected to DAW. 3 songs prepared with arrangement maps (Level 11 exercise 11). Full monitoring setup. Quiet room.",
      steps: [
        { text: "Prepare your 3 songs: choose three pieces that showcase different moods and techniques. Song 1: mellow/atmospheric (reggae or ambient). Song 2: groove-based (surf or funk). Song 3: energetic closer (uptempo). Each song should be 3-5 minutes.", why: "A demo is a curated showcase. Three songs is enough to demonstrate range without overstaying. The mood arc (mellow > groove > energy) is a natural journey that leaves the listener wanting more." },
        { text: "Record Song 1 via USB multi-track. Perform it clean — this is a take, not a practice run. If you make a major mistake, restart. Minor imperfections are fine — they prove it's live.", why: "The demo is your calling card. It represents your current best. Major mistakes (wrong key, dropped loops, long dead air) should be re-recorded. Minor timing imperfections, slight fader fumbles — these are evidence of live performance and add authenticity." },
        { text: "Record Songs 2 and 3 the same way. Take a breath between songs. Each song should feel like a complete performance, not a segment of a longer rehearsal.", why: "Breaks between songs let you reset mentally and physically. Each song gets full attention and full energy. A demo where song 3 sounds tired because you rushed through songs 1 and 2 defeats the purpose." },
        { text: "Mix in the DAW: for each song, adjust per-track levels for optimal balance. Add subtle reverb on dry tracks. Apply gentle master compression. Normalize the output so all three songs are at similar volume. Export each song as a WAV file (full quality) and an MP3 (for sharing).", why: "Post-production mixing is where 'good' becomes 'great.' The USB multi-track recording gives you individual control over every loop track. Small level adjustments, a touch of reverb, and volume normalization between songs transforms a live recording into a professional-sounding demo." },
        { text: "Listen to the complete demo front to back on three different playback systems: headphones, phone speaker, and car speakers (or computer speakers). The demo should sound good on ALL three. If it sounds bad on any system, adjust and re-export.", why: "Every playback system reveals different problems. Headphones reveal detail and noise. Phone speakers reveal mid-range balance (phone speakers have almost no bass). Car speakers reveal how the music holds up in a real-world listening environment. If the demo passes all three, it's ready to share." }
      ],
      feel: "Like printing your portfolio for the first time — everything you've learned, practiced, and refined is now in a tangible form that you can hand to someone and say 'this is what I do.' The demo is a promise. It says: 'if you book me, this is what you'll get.' Make it a promise you're proud to keep.",
      wrong: "Don't over-produce the demo — heavy DAW processing (auto-tune, sample replacement, extreme EQ) misrepresents your live capability. The demo should sound like a polished version of your live performance, not a studio fabrication. Also: don't include songs you can't reliably perform live. The demo is a promise, and you need to deliver on it.",
      sarah: "Gene, a demo is a promise — 'if you book me, this is what you'll get.' Three songs, professionally recorded, mixed, and mastered by you on your 505. That's not just a recording — it's proof that you're a production-quality loop artist. Share it. Post it. Send it to that coffee shop you've been eyeing for a live set. The demo opens doors.",
      metronome: 95,
      levelUp: "3-song demo recorded via USB multi-track, mixed in DAW, exported as WAV and MP3. Sounds good on headphones, phone speaker, and external speakers. Ready to share publicly."
    }
  ]
};
